fox.registerTemplate("legaldocs_personal_policy", [["div",{"data-fox-alias":"privacyText"},[["p",{},[["strong",{},[["textNode",{"text":"What does this Personal Data Policy cover?"}]]]]],["p",{},[["textNode",{"text":"This Personal Data Policy covers our treatment of information that we gather when you are accessing or using our Websites or Services or when you contact us in any manner. We gather various types of information, including information that identifies you as an individual (“Personal Information\") from our users, as explained in more detail below."}]]],["p",{},[["strong",{},[["textNode",{"text":"What information does ModelCentro Collect?"}]]]]],["p",{},[["strong",{},[["textNode",{"text":"Information You Provide to Us:"}]]]]],["p",{},[["i",{},[["textNode",{"text":"When you use the Websites: We may collect any Personal Information that you choose to send to us or provide to us, for example, on our “Technical Support\" page online form we may request your Username and your Email in order to assist you in solving technical issues with the site, we will keep a record of our correspondence."}]]]]],["p",{},[["i",{},[["textNode",{"text":"When you use the Services: We receive and store information you provide directly to us. For example, when subscribing to the site, we collect Personal Information, such as username and e-mail address, to provide you with the Services. The types of information we may collect directly from the users include: usernames, email addresses, social accounts usernames, location region, browser and operating system versions."}]]]]],["p",{},[["strong",{},[["textNode",{"text":"Information We Automatically Collect:"}]]]]],["p",{},[["i",{},[["textNode",{"text":"When you use the Websites:"}]]],["textNode",{"text":"When you visit the Websites, we collect certain information related to your device, such as your device’s IP address, referring website, what pages your device visited, and the time that your device visited our Website."}]]],["p",{},[["textNode",{"text":"We log information about our customers and their users when you use one of the Services including Internet Protocol (“IP\") address. Information collected by cookies and other similar technologies – we use various technologies to collect information which may include saving cookies to users’ computers."}]]],["p",{},[["textNode",{"text":"For further information, please see the section below headed “Cookies and other Tracking Technologies\"."}]]],["table",{"border":"1","cellpadding":"7","cellspacing":"0"},[["thead",{},[["tr",{},[["th",{"style":"white-space: nowrap;"},[["textNode",{"text":"Data collected"}]]],["th",{},[["textNode",{"text":"What is this"}]]],["th",{},[["textNode",{"text":"What it is needed for"}]]]]]]],["tbody",{},[["tr",{},[["td",{},[["textNode",{"text":"Username"}]]],["td",{},[["textNode",{"text":"Unique identification parameter (aka Nickname) that you choose when interact with the site"}]]],["td",{},[["textNode",{"text":"It is required in order to be able to identify and authorize you on the site. Also so performer can know how to address you"}]]]]],["tr",{},[["td",{},[["textNode",{"text":"Email Address"}]]],["td",{},[["textNode",{"text":"Your Email address"}]]],["td",{},[["textNode",{"text":"It is required in order to be able to identify and authorize you on the site. Also required for technical and marketing communication and communication with the performer"}]]]]],["tr",{},[["td",{},[["textNode",{"text":"Ip address"}]]],["td",{},[["textNode",{"text":"Internet Protocol address, see reference in "}],["a",{"href":"https://en.wikipedia.org/wiki/IP_address","target":"_blank","rel":"nofollow"},[["textNode",{"text":"Wikipedia"}]]]]],["td",{},[["textNode",{"text":"It is required in order to display offers and languages most appropriate for your region. Also used in as one of the account security measures and a billing security measure"}]]]]],["tr",{},[["td",{},[["textNode",{"text":"Geolocation"}]]],["td",{},[["textNode",{"text":"Country you are located in"}]]],["td",{},[["textNode",{"text":"Determined by the IP. It is required in order to display offers and languages most appropriate for your region"}]]]]],["tr",{},[["td",{},[["textNode",{"text":"Referring URL"}]]],["td",{},[["textNode",{"text":"Site that you came from to this site"}]]],["td",{},[["textNode",{"text":"Used for marketing and analytical purposes. Also used in Acquisition section of the Google Analytics and related sections"}]]]]],["tr",{},[["td",{},[["textNode",{"text":"Browser's agent"}]]],["td",{},[["textNode",{"text":"Version of your browser (example: Google Chrome v49.0)"}]]],["td",{},[["textNode",{"text":"Used in order to display technical version of the site fully functional and compatible with your browser's version and in order to be able to assist with any possible technical issues"}]]]]],["tr",{},[["td",{},[["textNode",{"text":"Plugins"}]]],["td",{},[["textNode",{"text":"Plugins available in your browser"}]]],["td",{},[["textNode",{"text":"One of the 'Account Security' measures. In combination with all other parameters it creates a single unique secure identifier so we can know that it is actually you and your account has not been compromised"}]]]]],["tr",{},[["td",{},[["textNode",{"text":"Fonts"}]]],["td",{},[["textNode",{"text":"Fonts package used in your browser"}]]],["td",{},[["textNode",{"text":"One of the 'Account Security' measures. In combination with all other parameters it creates a single unique secure identifier so we can know that it is actually you and your account has not been compromised"}]]]]],["tr",{},[["td",{},[["textNode",{"text":"Canvas"}]]],["td",{},[["textNode",{"text":"Hash of the footprint of the browser"}]]],["td",{},[["textNode",{"text":"One of the 'Account Security' measures. In combination with all other parameters it creates a single unique secure identifier so we can know that it is actually you and your account has not been compromised"}]]]]]]]]],["p",{},[["strong",{},[["textNode",{"text":"How do we use the information?"}]]]]],["p",{},[["i",{},[["textNode",{"text":"Websites:"}]]],["textNode",{"text":" We will use the information we collect via our Websites:"}]]],["ul",{},[["li",{},[["textNode",{"text":"To administer our Website, our events and for internal operations, including troubleshooting, data analysis, testing, statistical and survey purposes;"}]]],["li",{},[["textNode",{"text":"To improve our Website to ensure that content is presented in the most effective manner for you and for your computer;"}]]],["li",{},[["textNode",{"text":"Analyze customers’ use of the Websites for trend monitoring, marketing and advertising purposes;"}]]],["li",{},[["textNode",{"text":"For purposes made clear to you at the time you submit your information – for example, to fulfill your request to Subscribe to the newsletters, to provide you with access to the site."}]]],["li",{},[["textNode",{"text":"As part of our efforts to keep the Website safe and secure."}]]]]],["p",{},[["i",{},[["textNode",{"text":"Services:"}]]],["textNode",{"text":" We may use the information we collect from our customers and their users in connection with the Services we provide for a range of reasons, including to:"}]]],["ul",{},[["li",{},[["textNode",{"text":"To set up a user account;"}]]],["li",{},[["textNode",{"text":"Provide, operate and maintain the Services;"}]]],["li",{},[["textNode",{"text":"Manage our customers’ use of the Services, respond to enquiries and comments and provide customer service and support;"}]]],["li",{},[["textNode",{"text":"Send customers technical alerts, updates, security notifications, and administrative communications;"}]]],["li",{},[["textNode",{"text":"Investigate and prevent fraudulent activities, unauthorized access to the Services, and other illegal activities; and"}]]],["li",{},[["textNode",{"text":"For any other purposes about which we notify customers and users."}]]]]],["p",{},[["textNode",{"text":"We may also use the information you send to us via the Websites and/or Services, to communicate with you via email and, possibly, other means, regarding products, services, offers, promotions and events we think may be of interest to you or to send you our newsletter, if this is in accordance with your marketing preferences. However, you will always be able to opt-out of such communications at any time (see the “Your Choices\" section below)."}]]],["p",{},[["strong",{},[["textNode",{"text":"How do we share and disclose information to third parties?"}]]]]],["p",{},[["textNode",{"text":"We do not rent or sell your Personal Information to anyone. We may share and disclose information (including Personal Information) about our customers in the following limited circumstances:"}]]],["p",{},[["i",{},[["textNode",{"text":"Vendors, consultants and other service providers:"}]]],["textNode",{"text":" We may share your information with third party vendors, consultants\tand other service providers who we employ to perform tasks on our behalf. These companies include our payment processing providers ("}],["a",{"href":"https://centrobill.com/en/consumer/privacy.html","target":"_blank","rel":"nofollow"},[["textNode",{"text":"Centrobill"}]]],["textNode",{"text":"), website analytics companies ("}],["a",{"href":"https://www.google.com/policies/privacy/partners/ ","target":"_blank","rel":"nofollow"},[["textNode",{"text":"Google Analytics"}]]],["textNode",{"text":", "}],["a",{"href":"https://www.hotjar.com/legal/policies/privacy","target":"_blank","rel":"nofollow"},[["textNode",{"text":"Hotjar"}]]],["textNode",{"text":"), product feedback or help desk software providers (Kayako, Intercom), email service providers (Sendgrid), Account security provide(Exodentity), and others."}]]],["p",{},[["textNode",{"text":"If ModelCentro has received your Personal Information in the United States and subsequently transfers that information to a third party agent or service provider for processing, ModelCentro shall remain responsible for ensuring that such third party agent or service provider processes your Personal Information to the standard required by our Privacy Shield commitments (see the sections below headed “Additional Information for Users in the European Economic Area (\"EEA\") and \"International Data Transfers\"). Unless we tell you differently and you consent, our agents do not have any right to use the Personal Information we share with them beyond what is necessary to assist us."}]]],["p",{},[["i",{},[["textNode",{"text":"Performers: ModelCentro also shares your Personal information such as Username, Email address, IP(Internet Protocol) address with the owner of the site/profile you are subscribed to or interacted with. This is required in order for the site owner to be able to interact and communicate with the site’s subscribers."}]]]]],["p",{},[["i",{},[["textNode",{"text":"Protection of ModelCentro and Others:"}]]],["textNode",{"text":" We reserve the right to access, read, preserve, and disclose any information as necessary to comply with law or court order; enforce or apply our agreements with you and other agreements; or protect the rights, property, or safety of ModelCentro, our employees, our users, or others."}]]],["p",{},[["i",{},[["textNode",{"text":"Disclosures for National Security or Law Enforcement:"}]]],["textNode",{"text":" Under certain circumstances, we may be required to disclose your Personal Information in response to valid requests by public authorities, including to meet national security or law enforcement requirements."}]]],["p",{},[["strong",{},[["textNode",{"text":"Is Personal Information about me secure?"}]]]]],["p",{},[["textNode",{"text":"We use appropriate technical, organizational and administrative security measures to protect any information we hold in our records from loss, misuse, and unauthorized access, disclosure, alteration and destruction. Unfortunately, no company or service can guarantee complete security. Unauthorized entry or use, hardware or software failure, and other factors, may compromise the security of user information at any time. Among other practices, your account is protected by a password for your privacy and security. You must prevent unauthorized access to your account and Personal Information by selecting and protecting your password appropriately and limiting access to your computer or device and browser by signing off after you have finished accessing your account."}]]],["p",{},[["strong",{},[["textNode",{"text":"Cookies and other tracking technologies"}]]]]],["p",{},[["textNode",{"text":"Our Websites and some of our Services use cookies (small text files containing a string of alphanumeric characters that we put on your computer) and other similar tracking technologies (like web beacons, tags and scripts) to uniquely identify your browser and to gather information about how you interact with the Websites and Services. We use this information for the following purposes:"}]]],["ul",{},[["li",{},[["textNode",{"text":"Assisting you in navigation;"}]]],["li",{},[["textNode",{"text":"Assisting in registration, login, and your ability to provide feedback;"}]]],["li",{},[["textNode",{"text":"Analyzing your use of our products, services or applications; and"}]]],["li",{},[["textNode",{"text":"Assisting with our promotional and marketing efforts (including behavioral advertising)."}]]]]],["p",{},[["textNode",{"text":"Please consult our "}],["a",{"href":"/cookie-policy"},[["textNode",{"text":"Cookie Policy"}]]],["textNode",{"text":" for more information about the type of cookies and tracking technologies that we use on this Website and why, and how to accept and reject them."}]]],["p",{},[["textNode",{"text":"We also may use clear gifs in HTML-based emails sent to our users to track which emails are opened by recipients. This information is used to enable more accurate reporting, improve the effectiveness of our marketing, and make our Services and Websites better for our users."}]]],["p",{},[["textNode",{"text":"We also utilize Google Analytics, a web analysis service provided by Google, to better understand your use of our Websites and Services. Google Analytics collects information such as how often users visit the Websites, what pages they visit and what other sites they used prior to visiting. Google uses the data collected to track and examine the use of the Websites, to prepare reports on its activities and share them with other Google services. Google may use the data collected on the Websites to contextualize and personalize the ads of its own advertising network. Google’s ability to use and share information collected by Google Analytics about your visits to the Websites is restricted by the "}],["a",{"href":"https://www.google.com/analytics/terms/us.html","rel":"nofollow","target":"_blank"},[["textNode",{"text":"Google Analytics Terms of Use"}]]],["textNode",{"text":" and the "}],["a",{"href":"http://www.google.com/policies/privacy/","rel":"nofollow","target":"_blank"},[["textNode",{"text":"Google Privacy Policy"}]]],["textNode",{"text":". Google offers an opt-out mechanism for the web available "}],["a",{"href":"https://tools.google.com/dlpage/gaoptout/","rel":"nofollow","target":"_blank"},[["textNode",{"text":"here"}]]],["textNode",{"text":"."}]]],["p",{},[["strong",{},[["textNode",{"text":"Your Privacy Rights"}]]]]],["p",{},[["strong",{},[["textNode",{"text":"What choices do I have?"}]]]]],["p",{},[["textNode",{"text":"You can always opt not to disclose information to us, but keep in mind some information may be needed to register with us or to take advantage of some of our features."}]]],["p",{},[["strong",{},[["textNode",{"text":"Cookies"}]]]]],["p",{},[["textNode",{"text":"You can accept or reject cookies through our Cookies Preferences Center, accessible by clicking the “cookie settings\" button in our "}],["a",{"href":"/cookie-policy"},[["textNode",{"text":"Cookie Policy"}]]],["textNode",{"text":". You can also do so by adjusting your web browser controls. Please consult our "}],["a",{"href":"/cookie-policy"},[["textNode",{"text":"Cookie Policy"}]]],["textNode",{"text":" for more information about our use of cookies and how to accept and reject them."}]]],["p",{},[["strong",{},[["textNode",{"text":"Marketing Communications"}]]]]],["p",{},[["textNode",{"text":"You can opt-out of receiving certain promotional or marketing communications from us at any time, by using the unsubscribe link in the emails communications we send, we also not sending any promotional or marketing communication materials without having your consent for it."}]]],["p",{},[["strong",{},[["textNode",{"text":"How can I update and access my information (Exercise my Data Subject Rights)?"}]]]]],["p",{},[["textNode",{"text":"If you would like to access, review, update, rectify, and delete any Personal Information we hold about you, or exercise any other data subject right available to you under the EU General Data Protection Regulation (GDPR), you can either click the “Account Settings\"(Settings) link available in the site menu, or email us at "}],["a",{"data-name":"usersupport","data-domain":"modelcentro","data-tld":"com","class":"crypmail","onclick":"window.location.href = 'mailto:' + this.dataset.name + '@' + this.dataset.domain + '.' + this.dataset.tld"}]]],["p",{},[["textNode",{"text":"Our Privacy team will examine your request and respond to you as quickly as possible!"}]]],["p",{},[["textNode",{"text":"Please note that we may still use any aggregated and de-identified Personal Information that does not identify any individual, and may also retain and use your information as necessary to comply with our legal obligations, resolve disputes, and enforce our agreements."}]]],["p",{},[["strong",{},[["textNode",{"text":"California residents"}]]],["textNode",{"text":" are entitled to ask us for a notice identifying the categories of Personal Information which we share with our affiliates and/or third parties for marketing purposes, and providing contact information for such affiliates and/or third parties. If you are a California resident and would like a copy of this notice, please submit a written request to: "}],["a",{"data-name":"usersupport","data-domain":"modelcentro","data-tld":"com","class":"crypmail","onclick":"window.location.href = 'mailto:' + this.dataset.name + '@' + this.dataset.domain + '.' + this.dataset.tld"}]]],["p",{},[["textNode",{"text":"If you are a "}],["strong",{},[["textNode",{"text":"resident of the European Economic Area"}]]],["textNode",{"text":", please see the section below headed “Additional Information for users in the European Economic Area\" for further information about your privacy rights."}]]],["p",{},[["strong",{},[["textNode",{"text":"International Data Transfers"}]]]]],["p",{},[["textNode",{"text":"Personal Information you submit on the Websites or through the Services is sent to the United States and will be primarily processed by us in the United States and potentially in other countries, on our servers or on our hosted service providers’ cloud servers on our behalf. These countries may not have similar data protection laws to those in your country of residence. However, we will always protect your information in accordance with this Privacy Policy wherever it is processed. Some of our product offerings include the ability to host your data in servers located in the EU or other countries. To request this capability, contact "}],["a",{"data-name":"usersupport","data-domain":"modelcentro","data-tld":"com","class":"crypmail","onclick":"window.location.href = 'mailto:' + this.dataset.name + '@' + this.dataset.domain + '.' + this.dataset.tld"}]]],["p",{},[["strong",{},[["textNode",{"text":"Linked Websites"}]]]]],["p",{},[["textNode",{"text":"For your convenience, hyperlinks may be posted on the Websites that link to other websites (the “Linked Sites\"). We are not responsible for, and this Privacy Policy does not apply to, the privacy practices of any Linked Sites or of any companies that we do not own or control. Linked Sites may collect information in addition to that which we collect on the Websites. We do not endorse any of these Linked Sites, the services or products described or offered on such Linked Sites, or any of the content contained on the Linked Sites. We encourage you to seek out and read the privacy policy of each Linked Site that you visit to understand how the information that is collected about you is used and protected."}]]],["p",{},[["strong",{},[["textNode",{"text":"Will ModelCentro ever change this Personal Data Policy?"}]]]]],["p",{},[["textNode",{"text":"We’re constantly trying to improve our Websites and Services, so we may need to change this Personal Data Policy from time to time as well. We will alert you to material changes by, for example, placing a notice on our Websites and/or by sending you an email (if you have registered your e-mail details with us) when we are required to do so by applicable law. You can see when this Personal Data Policy was last updated by checking the date at the top of this page. You are responsible for periodically reviewing this Personal Data Policy."}]]],["p",{},[["strong",{},[["textNode",{"text":"What if I have questions about this policy?"}]]]]],["p",{},[["textNode",{"text":"If you have any questions or concerns regarding our privacy policies, please send us a detailed message to "}],["a",{"data-name":"support","data-domain":"modelcentro","data-tld":"com","class":"crypmail","onclick":"window.location.href = 'mailto:' + this.dataset.name + '@' + this.dataset.domain + '.' + this.dataset.tld"}],["textNode",{"text":", and we will try to resolve your concerns."}]]]]]]);
 /* fox-dynamic-injection */ 
