fox.registerTemplate("legaldocs_privacy_policy", [["div",{"data-fox-alias":"privacyText"},[["p",{"class":"title"},[["textNode",{"text":"Last Updated: February 20, 2020 "}]]],["p",{},[["strong",{},[["textNode",{"text":"Introduction"}]]]]],["p",{},[["textNode",{"text":"Welcome to our privacy policy."}]]],["p",{},[["textNode",{"text":" We respect your privacy and are committed to protecting your personal data. This privacy policy will inform you as to how we look after your personal data when you visit our website (regardless of where you visit it from) and tell you about your privacy rights and how the law protects you. "}]]],["p",{},[["textNode",{"text":"This privacy policy is provided in a layered format so you can click through to the specific areas set out below. Please also use the "}],["a",{"class":"anchorlink","data-target":"part_12"},[["textNode",{"text":"Glossary"}]]],["textNode",{"text":" to understand the meaning of some of the terms used in this privacy policy. "}]]],["ol",{},[["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_1"},[["textNode",{"text":"Important Information and Who We Are"}]]],["strong"]]]]],["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_2"},[["textNode",{"text":"The Data We Collect About You"}]]]]]]],["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_3"},[["textNode",{"text":"How Is Your Personal Data Collected"}]]]]]]],["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_4"},[["textNode",{"text":"How We Use Your Personal Data"}]]]]]]],["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_5"},[["textNode",{"text":"Disclosures of Your Personal Data"}]]]]]]],["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_6"},[["textNode",{"text":"International Transfers"}]]]]]]],["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_7"},[["textNode",{"text":"Data Security"}]]]]]]],["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_8"},[["textNode",{"text":"Data Retention"}]]]]]]],["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_9"},[["textNode",{"text":"Your EEA/UK Legal Rights"}]]]]]]],["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_10"},[["textNode",{"text":"Your California Privacy Rights"}]]]]]]],["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_11"},[["textNode",{"text":"Your Nevada Privacy Rights"}]]]]]]],["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_12"},[["textNode",{"text":"Your Canadian Privacy Rights"}]]]]]]],["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_13"},[["textNode",{"text":"Do Not Track Policy"}]]]]]]],["li",{},[["strong",{},[["a",{"class":"anchorlink","data-target":"part_14"},[["textNode",{"text":"Glossary"}]]]]]]]]],["p",{"id":"part_1"},[["strong",{},[["textNode",{"text":"1. Important information and who we are"}]]]]],["p",{},[["strong",{},[["textNode",{"text":"Purpose of this privacy policy"}]]]]],["p",{},[["textNode",{"text":"This privacy policy aims to give you information on how we collect and process your personal data through your use of this website, including any data you may provide through this website when you purchase a VIP membership, individual digital content, or a model product. "}]]],["p",{},[["textNode",{"text":"This website is not intended for children and we do not knowingly collect data relating to children. It is important that you read this privacy policy together with any other privacy policy or fair processing policy we may provide on specific occasions when we are collecting or processing personal data about you so that you are fully aware of how and why we are using your data. This privacy policy supplements other notices and privacy policies and is not intended to override them. "}]]],["p",{},[["strong",{},[["textNode",{"text":"Controller"}]]]]],["p",{},[["span",{},[],[["screenName","__text",true,[],"env"]]],["textNode",{"text":" is the controller and responsible for your personal data (collectively referred to as “Model”, “we”, “us”, or “our” in this privacy policy)."}]]],["p",{},[["textNode",{"text":" We have appointed a data privacy manager who is responsible for overseeing questions in relation to this privacy policy. If you have any questions about this privacy policy, including any requests to exercise "}],["a",{"class":"anchorlink","data-target":"part_9"},[["textNode",{"text":" your EEA/UK legal rights"}]]],["textNode",{"text":", please contact the data privacy manager using the details set out below. "}]]],["p",{},[["strong",{},[["textNode",{"text":"Contact details"}]]]]],["p",{},[["textNode",{"text":"If you have any questions about this privacy policy or our privacy practices, please contact our data privacy manager in the following ways: "}]]],["p",{},[["textNode",{"text":"Full name of legal entity: Centro Publisher Limited"}]]],["p",{},[["textNode",{"text":"Email address: "}],["a",{"href":"mailto:privacy@modelcentro.com"},[["textNode",{"text":" privacy@modelcentro.com"}]]]]],["p",{},[["textNode",{"text":"Postal address: Trust Company Complex, Ajeltaki Road, Ajeltaki Island, Majuro, Marshal Islands MH96960."}]]],["p",{},[["textNode",{"text":"If you reside in the United Kingdom (UK), you have the right to make a complaint at any time to the Information Commissioner’s Office (ICO), the UK supervisory authority for data protection issues ("}],["a",{"href":"https://www.ico.org.uk","target":"_blank"},[["textNode",{"text":"www.ico.org.uk"}]]],["textNode",{"text":"). If you reside within the European Economic Area (EEA), you have the right to make a complaint at any time to the appropriate supervisory authority for your country of residence. See "}],["a",{"href":"https://ec.europa.eu","target":"_blank"},[["textNode",{"text":"ec.europa.eu"}]]],["textNode",{"text":" for these details. If you reside outside the EEA or the UK, we will apply your legal rights as applicable to the data laws in the jurisdiction you are in. We would, however, appreciate the chance to deal with your concerns before you approach your supervisory authority so please contact us in the first instance. "}]]],["p",{},[["strong",{},[["textNode",{"text":"Changes to the privacy policy and your duty to inform us of changes"}]]]]],["p",{},[["textNode",{"text":"We keep our privacy policy under regular review. This version was last updated on February 20, 2020. Historic versions can be obtained by contacting us. "}]]],["p",{},[["textNode",{"text":"It is important that the personal data we hold about you is accurate and current. Please keep us informed if your personal data changes during your relationship with us. "}]]],["p",{},[["strong",{},[["textNode",{"text":"Third-party links"}]]]]],["p",{},[["textNode",{"text":"This website may include links to third-party websites, plug-ins, and applications. Clicking on those links or enabling those connections may allow third parties to collect or share data about you. We do not control these third-party websites and are not responsible for their privacy statements. When you leave our website, we encourage you to read the privacy policy of every website you visit. "}]]],["p",{"id":"part_2"},[["strong",{},[["textNode",{"text":"2. The data we collect about you"}]]]]],["p",{},[["textNode",{"text":"Personal data, or personal information, means any information about an individual from which that person can be identified. It does not include data where the identity has been removed (anonymous data). "}]]],["p",{},[["textNode",{"text":"We may collect, use, store, and transfer different kinds of personal data about you which we have grouped together as follows: "}]]],["ul",{},[["li",{},[["strong",{},[["textNode",{"text":"Identity Data "}]]],["textNode",{"text":"includes username or similar identifier."}]]],["li",{},[["strong",{},[["textNode",{"text":"Contact Data "}]]],["textNode",{"text":"includes email address."}]]],["li",{},[["strong",{},[["textNode",{"text":"Financial Data "}]]],["textNode",{"text":"includes payment card details. All payment data is stored by our payment processor and you should review its privacy policies and contact the payment processor directly to respond to your questions."}]]],["li",{},[["strong",{},[["textNode",{"text":"Transaction Data "}]]],["textNode",{"text":"includes details about payments from you and other details of products and services you have purchased from us."}]]],["li",{},[["strong",{},[["textNode",{"text":"Technical Data "}]]],["textNode",{"text":"includes internet protocol (IP) address, cookie ID, your login data, browser type and version, time zone setting and location, browser plug-in types and versions, operating system and platform, and other technology on the devices you use to access this website."}]]],["li",{},[["strong",{},[["textNode",{"text":"Profile Data "}]]],["textNode",{"text":"includes your username and password, purchases or orders made by you, your interests, preferences, feedback, and survey responses."}]]],["li",{},[["strong",{},[["textNode",{"text":"Usage Data "}]]],["textNode",{"text":"includes information about how you use our website, products, and services, including the full Uniform Resource Locators (URLs); clickstream to, through, and from our website (including date and time); content you viewed or searched for; page response times; download errors; length of visits to certain pages; page interaction information (such as scrolling, clicks, and mouse-overs); and methods used to browse away from the page."}]]],["li",{},[["strong",{},[["textNode",{"text":"Marketing and Communications Data "}]]],["textNode",{"text":" includes your preferences in receiving marketing from us and our third parties and your communication preferences."}]]]]],["p",{},[["textNode",{"text":"We also collect, use, and share "}],["strong",{},[["textNode",{"text":"Aggregated Data "}]]],["textNode",{"text":"such as statistical or demographic data for any purpose. Aggregated Data could be derived from your personal data but is not considered personal data in law as this data will not directly or indirectly reveal your identity. For example, we may aggregate your Usage Data to calculate the percentage of users accessing a specific website feature. However, if we combine or connect Aggregated Data with your personal data so that it can directly or indirectly identify you, we treat the combined data as personal data which will be used in accordance with this privacy policy. "}]]],["p",{},[["textNode",{"text":"We do not collect any "}],["strong",{},[["textNode",{"text":" Special Categories of Personal Data"}]]],["textNode",{"text":" about you (this includes details about your race or ethnicity, religious or philosophical beliefs, sex life, sexual orientation, political opinions, trade union membership, information about your health, and genetic and biometric data). Nor do we collect any information about criminal convictions and offenses. "}]]],["p",{},[["strong",{},[["textNode",{"text":"If you fail to provide personal data"}]]]]],["p",{},[["textNode",{"text":"Where we need to collect personal data by law, or under the terms of a contract we have with you and you fail to provide that data when requested, we may not be able to perform the contract we have or are trying to enter into with you (for example, to provide you with goods or services). In this case, we may have to cancel a product or service you have with us, but we will notify you if this is the case at the time. "}]]],["p",{"id":"part_3"},[["strong",{},[["textNode",{"text":"3. How is your personal data collected?"}]]]]],["p",{},[["textNode",{"text":"We use different methods to collect data from and about you, including through: "}]]],["ul",{},[["li",{},[["strong",{},[["textNode",{"text":"Direct interactions. "}]]],["textNode",{"text":" You may give us your Identity, Contact, and Financial Data by filling in forms or by corresponding with us by email or otherwise. This includes personal data you provide when you: "}],["ul",{},[["li",{},[["textNode",{"text":"apply for our products or services;"}]]],["li",{},[["textNode",{"text":"create an account on our website;"}]]],["li",{},[["textNode",{"text":"subscribe to our service;"}]]],["li",{},[["textNode",{"text":"request marketing to be sent to you;"}]]],["li",{},[["textNode",{"text":"enter a competition, promotion, or survey; or"}]]],["li",{},[["textNode",{"text":"give us feedback or contact us."}]]]]]]],["li",{},[["strong",{},[["textNode",{"text":"Automated technologies or interactions. "}]]],["textNode",{"text":"As you interact with our website, we will automatically collect Technical and Usage Data about your equipment, browsing actions, and patterns. We collect this personal data by using cookies, server logs, and other similar technologies. We may also receive Technical and Usage Data about you if you visit other websites employing our cookies. Please see our "}],["a",{"href":"/cookie-policy"},[["textNode",{"text":" cookie policy"}]]],["textNode",{"text":" for further details."}]]],["li",{},[["strong",{},[["textNode",{"text":"Third parties or publicly available sources."}]]],["textNode",{"text":" We will receive personal data about you from various third parties as set out below: "}],["ul",{"type":"circle"},[["li",{},[["textNode",{"text":"Technical Data from the following parties: "}],["ul",{},[["li",{},[["textNode",{"text":"analytics providers such as Google based outside the EU;"}]]],["li",{},[["textNode",{"text":"affiliates participating in our affiliate marketing program based inside and outside the EU; and"}]]],["li",{},[["textNode",{"text":"search information providers such as Google based outside the EU."}]]]]]]],["li",{},[["textNode",{"text":"Identity, Contact, and Transaction Data from providers of technical, payment, and delivery services such as Centro Publisher Limited based outside the EU and CentroBill based inside the EU. "}]]],["li",{},[["textNode",{"text":"Identity, Contact, and Technical Data from providers of customer support services such as Centro Publisher Limited based outside the EU. "}]]]]]]]]],["p",{"id":"part_4"},[["strong",{},[["textNode",{"text":"4. How we use your personal data"}]]]]],["p",{},[["textNode",{"text":"We will only use your personal data when the law allows us to. Most commonly, we will use your personal data in the following circumstances: "}],["ul",{"type":"sqwere"},[["li",{},[["textNode",{"text":"Where we need to perform the contract we are about to enter into or have entered into with you."}]]],["li",{},[["textNode",{"text":"Where it is necessary for our legitimate interests (or those of a third party) and your interests and fundamental rights do not override those interests."}]]],["li",{},[["textNode",{"text":"Where we need to comply with a legal obligation."}]]]]]]],["p",{},[["textNode",{"text":"Click "}],["a",{"class":"anchorlink","data-target":"part_12"},[["textNode",{"text":" here"}]]],["textNode",{"text":" to find out more about the types of lawful basis that we will rely on to process your personal data."}]]],["p",{},[["textNode",{"text":"Generally, we do not rely on consent as a legal basis for processing your personal data although we will get your consent before sending third-party direct marketing communications to you via email or text message. You have the right to withdraw consent to marketing at any time by contacting us."}]]],["p",{},[["strong",{},[["textNode",{"text":"Purposes for which we will use your personal data"}]]]]],["p",{},[["textNode",{"text":"We have set out below, in a table format, a description of all the ways we plan to use your personal data, and which of the legal bases we rely on to do so. We have also identified what our legitimate interests are where appropriate. "}]]],["p",{},[["textNode",{"text":"Note that we may process your personal data for more than one lawful ground depending on the specific purpose for which we are using your data. Please contact us if you need details about the specific legal ground we are relying on to process your personal data where more than one ground has been set out in the table below. "}]]],["p",{"class":"wrapper-cookie-table"},[["table",{"class":"list cookie-table"},[["tr",{},[["th",{},[["textNode",{"text":"Purpose/Activity "}]]],["th",{},[["textNode",{"text":"Type of data "}]]],["th",{},[["textNode",{"text":"Lawful basis for processing including basis of legitimate interest "}]]]]],["tr",{},[["td",{},[["textNode",{"text":"To register you as a new customer"}]]],["td",{},[["p",{},[["textNode",{"text":"(a) Identity "}]]],["p",{},[["textNode",{"text":"(b) Contact"}]]]]],["td",{},[["textNode",{"text":"Performance of a contract with you"}]]]]],["tr",{},[["td",{},[["p",{},[["textNode",{"text":"To process and deliver your order including:"}]]],["p",{},[["textNode",{"text":"(a) Manage payments, fees, and charges "}]]],["p",{},[["textNode",{"text":"(b) Collect and recover money owed to us "}]]]]],["td",{},[["p",{},[["textNode",{"text":"(a) Identity"}]]],["p",{},[["textNode",{"text":"(b) Contact"}]]],["p",{},[["textNode",{"text":"(c) Financial "}]]],["p",{},[["textNode",{"text":"(d) Transaction"}]]],["p",{},[["textNode",{"text":"(e) Marketing and Communications"}]]]]],["td",{},[["p",{},[["textNode",{"text":"(a) Performance of a contract with you"}]]],["p",{},[["textNode",{"text":"(b) Necessary for our legitimate interests (to recover debts due to us)"}]]]]]]],["tr",{},[["td",{},[["p",{},[["textNode",{"text":"To manage our relationship with you which will include:"}]]],["p",{},[["textNode",{"text":"(a) Notifying you about changes to our terms or privacy policy"}]]],["p",{},[["textNode",{"text":"(b) Asking you to leave a review or take a survey "}]]]]],["td",{},[["p",{},[["textNode",{"text":"(a) Identity"}]]],["p",{},[["textNode",{"text":"(b) Contact"}]]],["p",{},[["textNode",{"text":"(c) Profile"}]]],["p",{},[["textNode",{"text":"(d) Marketing and Communications"}]]]]],["td",{},[["p",{},[["textNode",{"text":"(a) Performance of a contract with you"}]]],["p",{},[["textNode",{"text":"(b) Necessary to comply with a legal obligation"}]]],["p",{},[["textNode",{"text":"(c) Necessary for our legitimate interests (to keep our records updated and to study how customers use our products/services)"}]]]]]]],["tr",{},[["td",{},[["p",{},[["textNode",{"text":"To enable you to partake in a prize draw, competition, or complete a survey"}]]]]],["td",{},[["p",{},[["textNode",{"text":"(a) Identity"}]]],["p",{},[["textNode",{"text":"(b) Contact"}]]],["p",{},[["textNode",{"text":"(c) Profile"}]]],["p",{},[["textNode",{"text":"(d) Usage"}]]],["p",{},[["textNode",{"text":"(e) Marketing and Communications"}]]]]],["td",{},[["p",{},[["textNode",{"text":"(a) Performance of a contract with you"}]]],["p",{},[["textNode",{"text":"(b) Necessary for our legitimate interests (to study how customers use our products/services, to develop them and grow our business)"}]]]]]]],["tr",{},[["td",{},[["p",{},[["textNode",{"text":"To administer and protect our business and this website (including troubleshooting, data analysis, testing, system maintenance, support, reporting, and hosting of data)"}]]]]],["td",{},[["p",{},[["textNode",{"text":"(a) Identity"}]]],["p",{},[["textNode",{"text":"(b) Contact"}]]],["p",{},[["textNode",{"text":"(c) Technical "}]]]]],["td",{},[["p",{},[["textNode",{"text":"(a) Necessary for our legitimate interests (for running our business, provision of administration and IT services, network security, to prevent fraud, and in the context of a business reorganization or group restructuring exercise) "}]]],["p",{},[["textNode",{"text":"(b) Necessary to comply with a legal obligation"}]]]]]]],["tr",{},[["td",{},[["p",{},[["textNode",{"text":"To deliver relevant website content and advertisements to you and measure or understand the effectiveness of the advertising we serve to you"}]]]]],["td",{},[["p",{},[["textNode",{"text":"(a) Identity"}]]],["p",{},[["textNode",{"text":"(b) Contact"}]]],["p",{},[["textNode",{"text":"(c) Profile"}]]],["p",{},[["textNode",{"text":"(d) Usage"}]]],["p",{},[["textNode",{"text":"(e) Marketing and Communications"}]]],["p",{},[["textNode",{"text":"(f) Technical"}]]]]],["td",{},[["p",{},[["textNode",{"text":"Necessary for our legitimate interests (to study how customers use our products/services, to develop them, to grow our business, and to inform our marketing strategy)"}]]]]]]],["tr",{},[["td",{},[["p",{},[["textNode",{"text":"To use data analytics to improve our website, products/services, marketing, customer relationships, and experiences"}]]]]],["td",{},[["p",{},[["textNode",{"text":"(a) Technical"}]]],["p",{},[["textNode",{"text":"(b) Usage"}]]]]],["td",{},[["p",{},[["textNode",{"text":"Necessary for our legitimate interests (to define types of customers for our products and services, to keep our website updated and relevant, to develop our business, and to inform our marketing strategy)"}]]]]]]],["tr",{},[["td",{},[["p",{},[["textNode",{"text":"To make suggestions and recommendations to you about goods or services that may be of interest to you"}]]]]],["td",{},[["p",{},[["textNode",{"text":"(a) Identity"}]]],["p",{},[["textNode",{"text":"(b) Contact"}]]],["p",{},[["textNode",{"text":"(c) Technical"}]]],["p",{},[["textNode",{"text":"(d) Usage"}]]],["p",{},[["textNode",{"text":"(e) Profile"}]]],["p",{},[["textNode",{"text":"(f) Marketing and Communications"}]]]]],["td",{},[["p",{},[["textNode",{"text":"Necessary for our legitimate interests (to develop our products/services and grow our business)"}]]]]]]]]]]],["p",{},[["strong",{},[["textNode",{"text":"Marketing"}]]]]],["p",{},[["textNode",{"text":"We strive to provide you with choices regarding certain personal data uses, particularly around marketing and advertising. We have established the following personal data control mechanisms:"}]]],["p",{},[["strong",{},[["textNode",{"text":"Promotional offers from us"}]]]]],["p",{},[["textNode",{"text":"We may use your Identity, Contact, Technical, Usage, and Profile Data to form a view on what we think you may want or need, or what may be of interest to you. This is how we decide which products, services, and offers may be relevant for you (we call this marketing). "}]]],["p",{},[["textNode",{"text":"You will receive marketing communications from us if you have requested information from us or purchased goods or services from us and you have not opted out of receiving that marketing. "}]]],["p",{},[["strong",{},[["textNode",{"text":"Third-party marketing"}]]]]],["p",{},[["textNode",{"text":"We will get your express opt-in consent before we share your personal data with any third party for marketing purposes. "}]]],["p",{},[["strong",{},[["textNode",{"text":"Opting out"}]]]]],["p",{},[["textNode",{"text":"You can ask us or third parties to stop sending you marketing messages at any time by logging into the website and checking or unchecking relevant boxes to adjust your marketing preferences, by following the opt-out links on any marketing messages sent to you, or by contacting us at any time. "}]]],["p",{},[["textNode",{"text":"Where you opt out of receiving these marketing messages, this will not apply to personal data provided to us as a result of a product/service purchase, product/service experience, or other transactions. "}]]],["p",{},[["strong",{},[["textNode",{"text":"Cookies"}]]]]],["p",{},[["textNode",{"text":"You can set your browser to refuse all or some browser cookies, or to alert you when websites set or access cookies. If you disable or refuse cookies, please note that some parts of this website may become inaccessible or not function properly. For more information about the cookies we use, please see our "}],["a",{"href":"/cookie_policy"},[["textNode",{"text":"cookie policy."}]]]]],["p",{},[["strong",{},[["textNode",{"text":"Change of purpose"}]]]]],["p",{},[["textNode",{"text":"We will only use your personal data for the purposes for which we collected it, unless we reasonably consider that we need to use it for another reason and that reason is compatible with the original purpose. If you wish to get an explanation as to how the processing for the new purpose is compatible with the original purpose, please contact us. "}]]],["p",{},[["textNode",{"text":"If we need to use your personal data for an unrelated purpose, we will notify you and we will explain the legal basis which allows us to do so. "}]]],["p",{},[["textNode",{"text":"Please note that we may process your personal data without your knowledge or consent, in compliance with the above rules, where this is required or permitted by law. "}]]],["p",{"id":"part_5"},[["strong",{},[["textNode",{"text":"5. Disclosures of your personal data"}]]]]],["p",{},[["textNode",{"text":"We may share your personal data with the parties set out below for the purposes stated in the table ("}],["a",{"class":"anchorlink","data-target":"part_1"},[["textNode",{"text":" Purposes for which we will use your personal data"}]]],["textNode",{"text":") above. "}],["ul",{},[["li",{},[["textNode",{"text":"External Third Parties as set out in the "}],["a",{"class":"anchorlink","data-target":"part_12"},[["textNode",{"text":" Glossary"}]]],["textNode",{"text":"."}]]],["li",{},[["textNode",{"text":"Third parties to whom we may choose to sell, transfer, or merge parts of our business or our assets. Alternatively, we may seek to acquire other businesses or merge with them. If a change happens to our business, then the new owners may use your personal data in the same way as set out in this privacy policy. "}]]]]]]],["p",{},[["textNode",{"text":"We require all third parties to respect the security of your personal data and to treat it in accordance with the law. We do not allow our third-party service providers to use your personal data for their own purposes and only permit them to process your personal data for specified purposes and in accordance with our instructions. "}]]],["p",{"id":"part_6"},[["strong",{},[["textNode",{"text":"6. International transfers"}]]]]],["p",{},[["textNode",{"text":"We are based in the Marshal Islands, but our servers are located in the Netherlands. We may process, store, and transfer personal data we collect, in and to a country outside your own, with different privacy laws that may or may not be comprehensive as your own. Where we do so, and where we are required to under local law, we will put in place appropriate mechanisms to ensure that your personal data receives an adequate level of protection where it is processed. "}]]],["p",{},[["textNode",{"text":"Unless you are located in the EEA or the UK, by submitting your personal data or engaging with the website or our application, you consent to this transfer, storing, or processing. "}]]],["p",{},[["textNode",{"text":"If you reside in the EEA or the UK, your personal data may be processed outside of the EEA or UK, including, for example, in the United States, so processing of your personal data will involve a transfer of data outside the EEA or UK."}]]],["p",{},[["textNode",{"text":"Whenever we transfer your personal data out of the EEA, we ensure a similar degree of protection is afforded to it by ensuring that the recipient third party agrees to contractual clauses. "}]]],["p",{},[["textNode",{"text":"Please contact us at "}],["a",{"href":"mailto:privacy@modelcentro.com"},[["textNode",{"text":" privacy@modelcentro.com"}]]],["textNode",{"text":" if you want further information on the specific mechanism used by us when transferring your personal data out of the EEA or UK."}]]],["p",{"id":"part_7"},[["strong",{},[["textNode",{"text":"7. Data security"}]]]]],["p",{},[["textNode",{"text":"We have put in place appropriate security measures to prevent your personal data from being accidentally lost, used, or accessed in an unauthorized way, altered or disclosed. In addition, we limit access to your personal data to those employees, agents, contractors, and other third parties who have a business need to know. They will only process your personal data on our instructions and they are subject to a duty of confidentiality. "}]]],["p",{},[["textNode",{"text":"We have put in place procedures to deal with any suspected personal data breach and will notify you and any applicable regulator of a breach where we are legally required to do so. "}]]],["p",{"id":"part_8"},[["strong",{},[["textNode",{"text":"8. Data retention"}]]]]],["p",{},[["strong",{},[["textNode",{"text":"How long will you use my personal data for?"}]]]]],["p",{},[["textNode",{"text":" We will only retain your personal data for as long as reasonably necessary to fulfill the purposes we collected it for, including for the purposes of satisfying any legal, regulatory, tax, accounting, or reporting requirements. We may retain your personal data for a longer period in the event of a complaint or if we reasonably believe there is a prospect of litigation in respect to our relationship with you. "}]]],["p",{},[["textNode",{"text":"To determine the appropriate retention period for personal data, we consider the amount, nature, and sensitivity of the personal data, the potential risk of harm from unauthorized use or disclosure of your personal data, the purposes for which we process your personal data and whether we can achieve those purposes through other means, and the applicable legal, regulatory, tax, accounting, or other requirements. "}]]],["p",{},[["textNode",{"text":"By law we have to keep basic information about our customers (including Contact, Identity, and Transaction Data) for seven years after they cease being customers for tax purposes. "}]]],["p",{},[["textNode",{"text":"In some circumstances you can ask us to delete your data: see "}],["a",{"class":"anchorlink","data-target":"part_9"},[["textNode",{"text":" your EEA/UK legal rights"}]]],["textNode",{"text":" below for further information. "}]]],["p",{},[["textNode",{"text":"In some circumstances we will anonymize your personal data (so that it can no longer be associated with you) for research or statistical purposes in which case we may use this information indefinitely without further notice to you. "}]]],["p",{"id":"part_9"},[["strong",{},[["textNode",{"text":"9. Your EEA/UK Legal Rights"}]]]]],["p",{},[["textNode",{"text":"Under certain circumstances, you have rights under data protection laws in relation to your personal data. Please click on the links below to find out more about these rights: "}],["ul",{},[["li",{},[["a",{"class":"anchorlink","data-target":"part_16"},[["textNode",{"text":"Request access to your personal data."}]]]]],["li",{},[["a",{"class":"anchorlink","data-target":"part_17"},[["textNode",{"text":"Request correction of your personal data."}]]]]],["li",{},[["a",{"class":"anchorlink","data-target":"part_18"},[["textNode",{"text":"Request erasure of your personal data."}]]]]],["li",{},[["a",{"class":"anchorlink","data-target":"part_19"},[["textNode",{"text":"Object to processing of your personal data."}]]]]],["li",{},[["a",{"class":"anchorlink","data-target":"part_20"},[["textNode",{"text":"Request restriction of processing your personal data."}]]]]],["li",{},[["a",{"class":"anchorlink","data-target":"part_21"},[["textNode",{"text":"Request transfer of your personal data."}]]]]],["li",{},[["a",{"class":"anchorlink","data-target":"part_22"},[["textNode",{"text":"Right to withdraw consent."}]]]]]]]]],["p",{},[["textNode",{"text":"If you wish to exercise any of the rights set out above, please contact us."}]]],["p",{},[["strong",{},[["textNode",{"text":"No fee usually required"}]]]]],["p",{},[["textNode",{"text":"You will not have to pay a fee to access your personal data (or to exercise any of the other rights). However, we may charge a reasonable fee if your request is clearly unfounded, repetitive, or excessive. Alternatively, we could refuse to comply with your request in these circumstances. "}]]],["p",{},[["strong",{},[["textNode",{"text":"What we may need from you"}]]]]],["p",{},[["textNode",{"text":"We may need to request specific information from you to help us confirm your identity and ensure your right to access your personal data (or to exercise any of your other rights). This is a security measure to ensure that personal data is not disclosed to any person who has no right to receive it. We may also contact you to ask you for further information in relation to your request to speed up our response. "}]]],["p",{},[["strong",{},[["textNode",{"text":"Time limit to respond"}]]]]],["p",{},[["textNode",{"text":"We try to respond to all legitimate requests within one month. Occasionally it could take us longer than a month if your request is particularly complex or you have made a number of requests. In this case, we will notify you and keep you updated. "}]]],["p",{"id":"part_10"},[["strong",{},[["textNode",{"text":"10. Your California privacy rights"}]]]]],["p",{},[["textNode",{"text":"If you are a California resident, California law may provide you with additional rights regarding our use of your personal data. To learn more about your California privacy rights, visit "}],["a",{"href":"/california-privacy-rights"},[["textNode",{"text":" CCPA"}]]],["textNode",{"text":". "}]]],["p",{},[["textNode",{"text":"California’s “Shine the Light” law (Civil Code Section 1798.83) permits our users who are California residents to request certain information regarding our disclosure of personal data to third parties for their direct marketing purposes. To make that request, please send an email to "}],["a",{"href":"mailto:privacy@modelcentro.com"},[["textNode",{"text":"privacy@modelcentro.com"}]]],["textNode",{"text":". "}]]],["p",{},[["textNode",{"text":"Further, if you are a California resident and would like to opt out from the disclosure of your personal data to any third party for direct marketing purposes, please send an email to "}],["a",{"href":"mailto:privacy@modelcentro.com"},[["textNode",{"text":"privacy@modelcentro.com"}]]],["textNode",{"text":". If you opt out from permitting your personal data to be shared, you may still receive selected offers directly from us in accordance with California law"}]]],["p",{"id":"part_11"},[["strong",{},[["textNode",{"text":" 11. Your Nevada Privacy Rights"}]]]]],["p",{},[["textNode",{"text":"Nevada residents who wish to exercise their sale opt-out rights under Nevada Revised Statutes Chapter 603A may submit a request to this designated address: "}],["a",{"href":"mailto:privacy@modelcentro.com"},[["textNode",{"text":"privacy@modelcentro.com"}]]],["textNode",{"text":". However, please know we do not currently sell data triggering that statute’s opt-out requirements. "}]]],["p",{"id":"part_12"},[["strong",{},[["textNode",{"text":" 12. Your Canadian Privacy Rights"}]]]]],["p",{},[["textNode",{"text":"We comply with Canadian Federal and Provincial privacy laws and regulations, including the Personal Information Protection and Electronic Documents Act. "}]]],["p",{},[["textNode",{"text":"We will only use your personal information for the purposes intended and as detailed in this policy unless we have obtained your consent to use it for other purposes. "}]]],["p",{},[["textNode",{"text":"Residents of Canada are notified that the personal data they provide to us is stored in our databases outside of Canada, including in the Netherlands, and may be subject to disclosure to authorized law enforcement or government agencies in response to lawful demand under the laws of that country."}]]],["p",{},[["textNode",{"text":"You may withdraw your consent to our personal data collection, use, or disclosure, subject to legal and contractual restrictions."}]]],["p",{},[["textNode",{"text":"You have the right to complain about our personal data handling practices."}]]],["p",{},[["textNode",{"text":"If you need to contact us about your personal data or believe that we have violated your privacy rights, please contact us at "}],["a",{"href":"mailto:privacy@modelcentro.com"},[["textNode",{"text":"privacy@modelcentro.com"}]]],["textNode",{"text":". You may visit "}],["a",{"target":"_blank","href":"https://www.priv.gc.ca/"},[["textNode",{"text":" www.priv.gc.ca"}]]],["textNode",{"text":" for more information about your privacy rights. "}]]],["p",{"id":"part_13"},[["strong",{},[["textNode",{"text":"13. Do Not Track policy"}]]]]],["p",{},[["textNode",{"text":"Do Not Track (“DNT”) is a privacy preference that you can set in your browser. DNT is a way for you to inform websites and services that you do not want certain information about your webpage visits collected over time and across websites or online services. We are committed to providing you with meaningful choices about the information we collect and that is why we provide you the ability to opt out. But we do not recognize or respond to any DNT signals as the Internet industry works toward defining exactly what DNT means, what it means to comply with DNT, and a common approach to responding to DNT. For more information, visit "}],["a",{"href":"https://www.allaboutdnt.com","target":"_blank"},[["textNode",{"text":"www.allaboutdnt.com"}]]],["textNode",{"text":". "}]]],["p",{"id":"part_14"},[["strong",{},[["textNode",{"text":"14. Glossary"}]]]]],["p",{},[["strong",{},[["textNode",{"text":"Lawful Basis"}]]]]],["p",{},[["strong",{},[["textNode",{"text":"Consent "}]]],["textNode",{"text":" means processing your personal data where you have signified your agreement by a statement or clear opt-in to processing for a specific purpose. Consent will only be valid if it is a freely given, specific, informed, and unambiguous indication of what you want. You can withdraw your consent at any time by contacting us."}]]],["p",{},[["strong",{},[["textNode",{"text":" Legitimate Interest"}]]],["textNode",{"text":" means the interest of our business in conducting and managing our business to enable us to give you the best service and the best and most secure experience. We make sure we consider and balance any potential impact on you (both positive and negative) and your rights before we process your personal data for our legitimate interests. We do not use your personal data for activities where our interests are overridden by the impact on you (unless we have your consent or are otherwise required or permitted to by law). You can obtain further information about how we assess our legitimate interests against any potential impact on you in respect of specific activities by contacting us. "}]]],["p",{},[["strong",{},[["textNode",{"text":" Performance of Contract"}]]],["textNode",{"text":" means processing your data where it is necessary for the performance of a contract to which you are a party or to take steps at your request before entering into such a contract. "}]]],["p",{},[["strong",{},[["textNode",{"text":" Comply with a legal obligation"}]]],["textNode",{"text":" means processing your personal data where it is necessary for compliance with a legal obligation that we are subject to. "}]]],["p",{},[["strong",{},[["textNode",{"text":"Third Parties"}]]]]],["p",{},[["strong",{},[["textNode",{"text":"External Third Parties"}]]]]],["ul",{},[["li",{},[["strong",{},[["textNode",{"text":"Compliance with Laws"}]]],["textNode",{"text":". We may disclose your information where we are legally required to do so to comply with applicable law, governmental requests, a judicial proceeding, court order, or legal process, such as in response to a court order or a subpoena (including in response to public authorities to meet national security or law enforcement requirements). "}]]],["li",{},[["strong",{},[["textNode",{"text":"Vital Interests and Legal Rights"}]]],["textNode",{"text":". We may disclose your information where we believe it is necessary to investigate, prevent, or take action regarding potential violations of our policies, suspected fraud, situations involving potential threats to the safety of any person and illegal activities, or as evidence in litigation in which we are involved. "}]]],["li",{},[["strong",{},[["textNode",{"text":"Vendors, Consultants, and Other Third-Party Service Providers"}]]],["textNode",{"text":". We may share your data with third-party vendors, service providers, contractors, or agents who perform services for us or on our behalf and require access to that information to do that work. Examples include: payment processing, data analysis, email delivery, hosting services, customer service, and marketing efforts. We may allow selected third parties to use tracking technology on the Website, which will enable them to collect data about how you interact with the Website over time. This information may be used to, among other things, analyze and track data, determine the popularity of certain content and better understand online activity. For example, we use Google Analytics to help us understand how our customers use the website (you can read more about how Google uses your personal data here: "}],["a",{"href":"https://policies.google.com/privacy?fg=1","target":"_blank"},[["textNode",{"text":" https://www.google.com/intl/en/policies/privacy/)"}]]],["textNode",{"text":". You can also optout of Google Analytics here: "}],["a",{"href":"https://tools.google.com/dlpage/gaoptout","target":"_blank"},[["textNode",{"text":" https://tools.google.com/dlpage/gaoptout"}]]],["textNode",{"text":". "}]]],["li",{},[["strong",{},[["textNode",{"text":"Affiliates"}]]],["textNode",{"text":". We may share your information with our affiliates, in which case we will require those affiliates to honor this privacy policy. "}]]]]],["p",{},[["strong",{},[["textNode",{"text":"Your Legal Rights"}]]]]],["p",{},[["textNode",{"text":" You have the right to: "}]]],["p",{"id":"part_15"},[["strong",{},[["textNode",{"text":"Request access"}]]],["textNode",{"text":" to your personal data (commonly known as a “data subject access request”). This enables you to receive a copy of the personal data we hold about you and to check that we are lawfully processing it. "}]]],["p",{"id":"part_16"},[["strong",{},[["textNode",{"text":"Request correction"}]]],["textNode",{"text":" of the personal data that we hold about you. This enables you to have any incomplete or inaccurate data we hold about you corrected, though we may need to verify the accuracy of the new data you provide to us."}]]],["p",{"id":"part_17"},[["strong",{},[["textNode",{"text":"Request erasure"}]]],["textNode",{"text":" of your personal data. This enables you to ask us to delete or remove personal data where there is no good reason for us continuing to process it. You also have the right to ask us to delete or remove your personal data where you have successfully exercised your right to object to processing (see below), where we may have processed your information unlawfully, or where we are required to erase your personal data to comply with local law. Note, however, that we may not always be able to comply with your request of erasure for specific legal reasons which will be notified to you, if applicable, at the time of your request."}]]],["p",{"id":"part_18"},[["strong",{},[["textNode",{"text":"Object to processing "}]]],["textNode",{"text":"of your personal data where we are relying on a legitimate interest (or those of a third party) and there is something about your particular situation which makes you want to object to processing on this ground as you feel it impacts on your fundamental rights and freedoms. You also have the right to object where we are processing your personal data for direct marketing purposes. In some cases, we may demonstrate that we have compelling legitimate grounds to process your information which override your rights and freedoms."}]]],["p",{"id":"part_19"},[["strong",{},[["textNode",{"text":"Request restriction of processing"}]]],["textNode",{"text":" of your personal data. This enables you to ask us to suspend the processing of your personal data in the following scenarios: "}],["ul",{},[["li",{},[["textNode",{"text":"If you want us to establish the data’s accuracy."}]]],["li",{},[["textNode",{"text":"Where our use of the data is unlawful but you do not want us to erase it."}]]],["li",{},[["textNode",{"text":"Where you need us to hold the data even if we no longer require it as you need it to establish, exercise, or defend legal claims."}]]],["li",{},[["textNode",{"text":"You have objected to our use of your data but we need to verify whether we have overriding legitimate grounds to use it."}]]]]]]],["p",{"id":"part_20"},[["strong",{},[["textNode",{"text":"Request the transfer "}]]],["textNode",{"text":"of your personal data to you or to a third party. We will provide to you, or a third party you have chosen, your personal data in a structured, commonly used, machine-readable format. Note that this right only applies to automated information which you initially provided consent for us to use or where we used the information to perform a contract with you."}]]],["p",{"id":"part_21"},[["strong",{},[["textNode",{"text":"Withdraw consent at any time"}]]],["textNode",{"text":" where we are relying on consent to process your personal data. However, this will not affect the lawfulness of any processing carried out before you withdraw your consent. If you withdraw your consent, we may not be able to provide certain products or services to you. We will advise you if this is the case at the time you withdraw your consent. "}]]]]]]);
